-- SPOTIFY REVENUE PROJECT - TABLE CREATION

-- 1. USERS
CREATE TABLE users (
    user_id INT PRIMARY KEY,
    username VARCHAR(100),
    email VARCHAR(255) UNIQUE,
    country VARCHAR(100),
    signup_date DATE,
    birth_year INT,
    gender VARCHAR(20),
    account_status VARCHAR(50)
);

-- 2. SUBSCRIPTION_PLANS
CREATE TABLE subscription_plans (
    plan_id INT PRIMARY KEY,
    plan_name VARCHAR(100),
    monthly_price DECIMAL(5,2),
    billing_cycle VARCHAR(50),
    ad_supported BIT,
    max_accounts INT,
    student_discount_pct DECIMAL(5,2),
    plan_status VARCHAR(50)
);

-- 3. PROMOTIONS
CREATE TABLE promotions (
    promo_id INT PRIMARY KEY,
    promo_name VARCHAR(255),
    discount_pct INT,
    start_date DATE,
    end_date DATE,
    promo_status VARCHAR(50),
    promotion_country VARCHAR(100)
);

-- 4. ARTISTS
CREATE TABLE artists (
    artist_id INT PRIMARY KEY,
    artist_name VARCHAR(255),
    country VARCHAR(100),
    debut_year INT,
    label_name VARCHAR(255),
    monthly_listeners_mil DECIMAL(10,2)
);

-- 5. ALBUMS
CREATE TABLE albums (
    album_id INT PRIMARY KEY,
    artist_id INT,
    album_name VARCHAR(255),
    release_date DATE,
    album_type VARCHAR(50),
    total_tracks INT,
    FOREIGN KEY (artist_id) REFERENCES artists(artist_id)
);

-- 6. TRACKS
CREATE TABLE tracks (
    track_id INT PRIMARY KEY,
    album_id INT,
    track_name VARCHAR(255),
    duration_seconds INT,
    explicit_flag BIT,
    popularity_score INT,
    royalty_rate DECIMAL(10,4),
    release_date DATE,
    FOREIGN KEY (album_id) REFERENCES albums(album_id)
);

-- 7. GENRES
CREATE TABLE genres (
    genre_id INT PRIMARY KEY,
    genre_name VARCHAR(100),
    genre_group VARCHAR(100)
);

-- 8. TRACK_GENRES
CREATE TABLE track_genres (
    track_id INT,
    genre_id INT,
    PRIMARY KEY (track_id, genre_id),
    FOREIGN KEY (track_id) REFERENCES tracks(track_id),
    FOREIGN KEY (genre_id) REFERENCES genres(genre_id)
);

-- 9. USER_SUBSCRIPTIONS
CREATE TABLE user_subscriptions (
    subscription_id INT PRIMARY KEY,
    user_id INT,
    plan_id INT,
    promo_id INT,
    start_date DATE,
    end_date DATE,
    subscription_status VARCHAR(50),
    auto_renew BIT,
    previous_plan_id INT,
    change_type VARCHAR(50),
    tenure_months INT,
    FOREIGN KEY (user_id) REFERENCES users(user_id),
    FOREIGN KEY (plan_id) REFERENCES subscription_plans(plan_id),
    FOREIGN KEY (promo_id) REFERENCES promotions(promo_id)
);

-- 10. PAYMENTS
CREATE TABLE payments (
    payment_id INT PRIMARY KEY,
    subscription_id INT,
    payment_date DATE,
    amount DECIMAL(10,2),
    payment_method VARCHAR(50),
    payment_status VARCHAR(50),
    invoice_month DATE,
    refund_amount DECIMAL(10,2),
    FOREIGN KEY (subscription_id) REFERENCES user_subscriptions(subscription_id)
);

-- 11. LISTENING_EVENTS
CREATE TABLE listening_events (
    event_id INT PRIMARY KEY,
    user_id INT,
    track_id INT,
    played_at DATETIME,
    listen_seconds INT,
    completed_flag BIT,
    skipped_flag BIT,
    device_type VARCHAR(50),
    platform VARCHAR(50),
    session_id VARCHAR(50),
    FOREIGN KEY (user_id) REFERENCES users(user_id),
    FOREIGN KEY (track_id) REFERENCES tracks(track_id)
);

