-- table confirmation --

Select * FROM users;

select * FROM subscription_plans;

select * from promotions;

select * from artists;

select * from albums;

select * from tracks;

select * from genres;

select * from track_genres;

select * from user_subscriptions;

select * from payments;

select * from listening_events;

--1 Revenue by subscription plan--

SELECT 
    sp.plan_name,
    COUNT(DISTINCT us.subscription_id) AS total_subscriptions,
    SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS collected_revenue,
    SUM(CASE WHEN p.payment_status = 'Refunded' THEN p.refund_amount ELSE 0 END) AS refunded_revenue,
    SUM(CASE WHEN p.payment_status = 'Failed' THEN p.amount ELSE 0 END) AS failed_payment_value
FROM subscription_plans sp
JOIN user_subscriptions us
    ON sp.plan_id = us.plan_id
LEFT JOIN payments p
    ON us.subscription_id = p.subscription_id
GROUP BY sp.plan_name
ORDER BY collected_revenue DESC;

--2 Net revenue by plan--

SELECT 
    sp.plan_name,
    SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END)
      - SUM(CASE WHEN p.payment_status = 'Refunded' THEN p.refund_amount ELSE 0 END) AS net_revenue
FROM subscription_plans sp
JOIN user_subscriptions us
    ON sp.plan_id = us.plan_id
LEFT JOIN payments p
    ON us.subscription_id = p.subscription_id
GROUP BY sp.plan_name
ORDER BY net_revenue DESC;

--3 Revenue by Country--

SELECT 
    u.country,
    SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS collected_revenue,
    SUM(CASE WHEN p.payment_status = 'Refunded' THEN p.refund_amount ELSE 0 END) AS refunded_revenue,
    COUNT(DISTINCT u.user_id) AS total_users
FROM users u
JOIN user_subscriptions us
    ON u.user_id = us.user_id
LEFT JOIN payments p
    ON us.subscription_id = p.subscription_id
GROUP BY u.country
ORDER BY collected_revenue DESC;

--4 Promotion Performance--

SELECT 
    pr.promo_name,
    pr.promotion_country,
    COUNT(DISTINCT us.subscription_id) AS subscriptions_using_promo,
    SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS promo_revenue
FROM promotions pr
JOIN user_subscriptions us
    ON pr.promo_id = us.promo_id
LEFT JOIN payments p
    ON us.subscription_id = p.subscription_id
GROUP BY pr.promo_name, pr.promotion_country
ORDER BY promo_revenue DESC;

--5 Payment status breakdown--

SELECT 
    payment_status,
    COUNT(*) AS total_payments,
    SUM(amount) AS total_amount,
    SUM(refund_amount) AS total_refunded
FROM payments
GROUP BY payment_status
ORDER BY total_payments DESC;

--6 Subscription lifecycle analysis--

SELECT 
    change_type,
    COUNT(*) AS total_changes,
    AVG(tenure_months * 1.0) AS avg_tenure_months
FROM user_subscriptions
GROUP BY change_type
ORDER BY total_changes DESC;

--7 Average tenure by plan--

SELECT 
    sp.plan_name,
    AVG(us.tenure_months * 1.0) AS avg_tenure_months,
    COUNT(*) AS total_subscriptions
FROM user_subscriptions us
JOIN subscription_plans sp
    ON us.plan_id = sp.plan_id
GROUP BY sp.plan_name
ORDER BY avg_tenure_months DESC;

--8 Most engaged users--

SELECT TOP 10
    le.user_id,
    COUNT(*) AS total_streams,
    COUNT(DISTINCT le.session_id) AS total_sessions,
    AVG(le.listen_seconds * 1.0) AS avg_listen_seconds
FROM listening_events le
GROUP BY le.user_id
ORDER BY total_streams DESC;

--9: Do paid plans have stronger engagement?--

SELECT 
    sp.plan_name,
    COUNT(DISTINCT le.user_id) AS active_listeners,
    COUNT(le.event_id) AS total_streams,
    COUNT(DISTINCT le.session_id) AS total_sessions,
    AVG(le.listen_seconds * 1.0) AS avg_listen_seconds
FROM listening_events le
JOIN user_subscriptions us
    ON le.user_id = us.user_id
JOIN subscription_plans sp
    ON us.plan_id = sp.plan_id
GROUP BY sp.plan_name
ORDER BY total_streams DESC;

--10: Genre popularity--

SELECT TOP 10
    g.genre_name,
    COUNT(*) AS total_streams
FROM listening_events le
JOIN tracks t
    ON le.track_id = t.track_id
JOIN track_genres tg
    ON t.track_id = tg.track_id
JOIN genres g
    ON tg.genre_id = g.genre_id
GROUP BY g.genre_name
ORDER BY total_streams DESC;

--11: Top artists by streams--

SELECT TOP 10
    a.artist_name,
    COUNT(*) AS total_streams
FROM listening_events le
JOIN tracks t
    ON le.track_id = t.track_id
JOIN albums al
    ON t.album_id = al.album_id
JOIN artists a
    ON al.artist_id = a.artist_id
GROUP BY a.artist_name
ORDER BY total_streams DESC;

--12: CTE for high-value users--

WITH user_revenue AS (
    SELECT 
        us.user_id,
        SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS total_paid_revenue
    FROM user_subscriptions us
    LEFT JOIN payments p
        ON us.subscription_id = p.subscription_id
    GROUP BY us.user_id
)
SELECT TOP 10
    u.user_id,
    u.username,
    u.country,
    ur.total_paid_revenue
FROM user_revenue ur
JOIN users u
    ON ur.user_id = u.user_id
ORDER BY ur.total_paid_revenue DESC;

--13: Window function for country revenue ranking--

WITH country_revenue AS (
    SELECT 
        u.country,
        SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS revenue
    FROM users u
    JOIN user_subscriptions us
        ON u.user_id = us.user_id
    LEFT JOIN payments p
        ON us.subscription_id = p.subscription_id
    GROUP BY u.country
)
SELECT 
    country,
    revenue,
    RANK() OVER (ORDER BY revenue DESC) AS revenue_rank
FROM country_revenue;

--Predict which users are high-value (generate high revenue) Data Science--

--Top 25% of users by total paid revenue = high_value_user = 1 or else 0--

WITH user_revenue AS (
    SELECT 
        us.user_id,
        SUM(CASE WHEN p.payment_status = 'Paid' THEN p.amount ELSE 0 END) AS total_paid_revenue
    FROM user_subscriptions us
    LEFT JOIN payments p
        ON us.subscription_id = p.subscription_id
    GROUP BY us.user_id
),

user_behavior AS (
    SELECT 
        le.user_id,
        COUNT(*) AS total_streams,
        COUNT(DISTINCT le.session_id) AS total_sessions,
        AVG(le.listen_seconds * 1.0) AS avg_listen_seconds,
        AVG(CASE WHEN le.skipped_flag = 1 THEN 1.0 ELSE 0 END) AS skip_rate
    FROM listening_events le
    GROUP BY le.user_id
),

user_subscription_features AS (
    SELECT 
        us.user_id,
        MAX(us.tenure_months) AS tenure_months,
        MAX(CAST(us.auto_renew AS INT)) AS auto_renew
    FROM user_subscriptions us
    GROUP BY us.user_id
),

modeling_dataset AS (
    SELECT 
        u.user_id,
        u.country,
        ISNULL(ur.total_paid_revenue, 0) AS total_paid_revenue,
        ISNULL(usf.tenure_months, 0) AS tenure_months,
        ISNULL(usf.auto_renew, 0) AS auto_renew,
        ISNULL(ub.total_streams, 0) AS total_streams,
        ISNULL(ub.total_sessions, 0) AS total_sessions,
        ISNULL(ub.avg_listen_seconds, 0) AS avg_listen_seconds,
        ISNULL(ub.skip_rate, 0) AS skip_rate
    FROM users u
    LEFT JOIN user_revenue ur
        ON u.user_id = ur.user_id
    LEFT JOIN user_behavior ub
        ON u.user_id = ub.user_id
    LEFT JOIN user_subscription_features usf
        ON u.user_id = usf.user_id
),

ranked_users AS (
    SELECT *,
           NTILE(4) OVER (ORDER BY total_paid_revenue DESC) AS revenue_quartile
    FROM modeling_dataset
)

SELECT *,
       CASE WHEN revenue_quartile = 1 THEN 1 ELSE 0 END AS high_value_user
FROM ranked_users
ORDER BY total_paid_revenue DESC;















